/// Projector that updates Permission projection from events
pub struct PermissionProjector<R: PermissionProjectionRepository> {
    repository: Arc<R>,
}

impl<R: PermissionProjectionRepository> PermissionProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: PermissionEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "PermissionCreatedEvent" => {
                let created: PermissionCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "PermissionUpdatedEvent" => {
                let updated: PermissionUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "PermissionDeletedEvent" => {
                let deleted: PermissionDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: PermissionProjectionRepository> PermissionEventHandler for PermissionProjector<R> {

    async fn on_created(&self, event: PermissionCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = PermissionProjection::new(
            event.id,
            event.name,
            event.description,
            event.resource,
            event.action,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: PermissionUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.name = event.name;
            projection.description = event.description;
            projection.resource = event.resource;
            projection.action = event.action;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: PermissionDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

